#pragma OPENCL EXTENSION cl_khr_fp64 : enable

typedef struct latLong
{
  float lat;
  float lng;
} LatLong;

typedef struct record
{
  char recString[53];
  float distance;
} Record;

__kernel void euclid(__global LatLong *d_locations, __global float *d_distances, int numRecords, float lat, float lng)
{
    // Calculate linear global ID manually to support 1D or 2D launch configurations
    // This mimics the CUDA flattening: blockDim.x * (gridDim.x * blockIdx.y + blockIdx.x) + threadIdx.x
    // In OpenCL: global_id_x + global_id_y * global_size_x
    size_t globalId = get_global_id(0);
    if (get_global_dim() > 1) {
        globalId += get_global_id(1) * get_global_size(0);
    }
    if (get_global_dim() > 2) {
        globalId += get_global_id(2) * get_global_size(0) * get_global_size(1);
    }

    if (globalId < numRecords) {
        LatLong loc = d_locations[globalId];
        float diff_lat = lat - loc.lat;
        float diff_lng = lng - loc.lng;
        d_distances[globalId] = sqrt(diff_lat * diff_lat + diff_lng * diff_lng);
    }
}
